// plugins/oper-log.ts
function operLogPlugin() {
  const routerHooksMap = new Map;
  return new Elysia({ name: "oper-log-plugin" }).on("start", (app) => {
    app.getGlobalRoutes().forEach((route) => {
      routerHooksMap.set(`${route.method}:::${route.path}`, route.hooks || {});
    });
  }).derive({ as: "global" }, (ctx) => {
    const startTime = Date.now();
    const operLog = {
      log: async (data) => {
        const request = ctx.request;
        const userId = ctx.userId ?? null;
        const username = ctx.session?.username ?? "";
        const ip2 = ctx.server?.requestIP(request);
        return log3({
          ...data,
          method: request.method,
          url: new URL(request.url).pathname,
          ip: ip2 ? `${ip2.address}:${ip2.port}` : null,
          userId,
          username,
          costTime: Date.now() - startTime
        });
      }
    };
    return { operLog, __operLogStartTime: startTime };
  }).onAfterHandle({ as: "global" }, async (ctx) => {
    const hooks = routerHooksMap.get(`${ctx.request.method}:::${ctx.route}`) || {};
    const operLogConfig = hooks?.detail?.operLog;
    if (!operLogConfig || operLogConfig.skip)
      return;
    const request = ctx.request;
    const userId = ctx.userId ?? null;
    const username = ctx.session?.username ?? "";
    const ip2 = ctx.server?.requestIP(request);
    const startTime = ctx.__operLogStartTime ?? Date.now();
    await log3({
      title: operLogConfig.title,
      type: operLogConfig.type ?? "other",
      method: request.method,
      url: new URL(request.url).pathname,
      ip: ip2 ? `${ip2.address}:${ip2.port}` : null,
      status: 1,
      userId,
      username,
      costTime: Date.now() - startTime
    });
  }).onError({ as: "global" }, async (ctx) => {
    const hooks = routerHooksMap.get(`${ctx.request.method}:::${ctx.route}`) || {};
    const operLogConfig = hooks?.detail?.operLog;
    if (!operLogConfig || operLogConfig.skip)
      return;
    const request = ctx.request;
    const userId = ctx.userId ?? null;
    const username = ctx.session?.username ?? "";
    const ip2 = ctx.server?.requestIP(request);
    const startTime = ctx.__operLogStartTime ?? Date.now();
    const error = ctx.error;
    await log3({
      title: operLogConfig.title,
      type: operLogConfig.type ?? "other",
      method: request.method,
      url: new URL(request.url).pathname,
      ip: ip2 ? `${ip2.address}:${ip2.port}` : null,
      status: 0,
      errorMsg: error?.message || String(error),
      userId,
      username,
      costTime: Date.now() - startTime
    });
  });
}

