// services/job.ts
var Job = model.job;
var JobLog2 = model.job_log;
var handlers2 = new Map;
var cronInstances = new Map;
var pendingCrons = [];
var started = false;
async function findAll9(query2, ctx) {
  const page2 = query2?.page ?? 1;
  const pageSize = query2?.pageSize ?? 10;
  const offset = (page2 - 1) * pageSize;
  const where2 = buildWhere(Job.tableName, query2?.filter, ctx);
  const data = await Job.findMany({
    where: where2,
    limit: pageSize,
    offset,
    orderBy: [{ column: "id", order: "DESC" }]
  });
  const total = await Job.count(where2);
  return { data, total, page: page2, pageSize };
}
async function findById9(id, ctx) {
  return Job.findOne({ where: buildWhere(Job.tableName, `id = ${id}`, ctx) });
}
async function create8(data, ctx) {
  if (!checkCreateScope(Job.tableName, data, ctx))
    return null;
  const result = await Job.create(data);
  if (result && data.status === 1) {
    scheduleJob(result);
  }
  return result;
}
async function update5(id, data, ctx) {
  const w2 = buildWhere(Job.tableName, `id = ${id}`, ctx);
  if (!w2)
    return null;
  const n2 = await Job.updateMany(w2, data);
  if (n2 === 0)
    return null;
  const result = await Job.getOne(id);
  if (result)
    await reload3(id);
  return result;
}
async function remove10(id, ctx) {
  if (cronInstances.has(id)) {
    cronInstances.get(id).stop();
    cronInstances.delete(id);
  }
  const w2 = buildWhere(Job.tableName, `id = ${id}`, ctx);
  if (!w2)
    return false;
  return await Job.deleteMany(w2) > 0;
}
function register2(handler, fn) {
  handlers2.set(handler, fn);
}
function registerCron(def) {
  pendingCrons.push(def);
}
function getHandlerNames() {
  return Array.from(handlers2.keys());
}
async function start() {
  if (started)
    return;
  started = true;
  await syncCronsToDb();
  const jobs = await Job.findMany({ where: `status = 1` });
  for (const job of jobs) {
    scheduleJob(job);
  }
  console.log(`\u2705 Job scheduler started: ${jobs.length} jobs`);
}
async function syncCronsToDb() {
  for (const def of pendingCrons) {
    const group = def.group || "default";
    const existing = await Job.findOne({
      where: `handler = '${def.handler}' && group = '${group}'`
    });
    if (existing) {
      if (existing.cron !== def.cron || existing.name !== def.name) {
        await Job.update(existing.id, {
          cron: def.cron,
          name: def.name,
          remark: def.remark || existing.remark
        });
      }
    } else {
      await Job.create({
        handler: def.handler,
        group,
        name: def.name,
        cron: def.cron,
        params: def.params ? JSON.stringify(def.params) : null,
        remark: def.remark || null,
        status: 1
      });
    }
  }
}
function scheduleJob(job) {
  if (cronInstances.has(job.id)) {
    cronInstances.get(job.id).stop();
  }
  const cron = new E2(job.cron, async () => {
    await executeJob(job.id);
  });
  cronInstances.set(job.id, cron);
}
async function executeJob(jobId, manualParams) {
  const job = await Job.findOne({ where: `id = ${jobId}` });
  if (!job)
    return { success: false, error: "\u4EFB\u52A1\u4E0D\u5B58\u5728" };
  const handler = handlers2.get(job.handler);
  if (!handler)
    return { success: false, error: `\u5904\u7406\u51FD\u6570 ${job.handler} \u672A\u6CE8\u518C` };
  const startTime = new Date;
  const params = manualParams ?? (job.params ? JSON.parse(job.params) : undefined);
  try {
    await handler(params);
    const endTime = new Date;
    const costTime = endTime.getTime() - startTime.getTime();
    await JobLog2.create({
      jobId: job.id,
      jobName: job.name,
      handler: job.handler,
      message: "\u6267\u884C\u6210\u529F",
      status: 1,
      startTime: startTime.toISOString(),
      endTime: endTime.toISOString(),
      costTime
    });
    return { success: true, message: "\u6267\u884C\u6210\u529F" };
  } catch (err) {
    const endTime = new Date;
    const costTime = endTime.getTime() - startTime.getTime();
    const errorMsg = err instanceof Error ? err.message : String(err);
    await JobLog2.create({
      jobId: job.id,
      jobName: job.name,
      handler: job.handler,
      message: "\u6267\u884C\u5931\u8D25",
      status: 0,
      errorMsg,
      startTime: startTime.toISOString(),
      endTime: endTime.toISOString(),
      costTime
    });
    return { success: false, error: errorMsg };
  }
}
async function enable(jobId) {
  await Job.update(jobId, { status: 1 });
  const job = await Job.findOne({ where: `id = ${jobId}` });
  if (job)
    scheduleJob(job);
}
async function disable(jobId) {
  await Job.update(jobId, { status: 0 });
  if (cronInstances.has(jobId)) {
    cronInstances.get(jobId).stop();
    cronInstances.delete(jobId);
  }
}
async function reload3(jobId) {
  const job = await Job.findOne({ where: `id = ${jobId}` });
  if (!job)
    return;
  if (job.status === 1) {
    scheduleJob(job);
  } else {
    if (cronInstances.has(jobId)) {
      cronInstances.get(jobId).stop();
      cronInstances.delete(jobId);
    }
  }
}
register2("clearExpiredSessions", async () => {
  await cleanup();
  console.log("\u2705 Cleared expired sessions");
});
registerCron({
  handler: "clearExpiredSessions",
  group: "system",
  name: "\u6E05\u7406\u8FC7\u671F\u4F1A\u8BDD",
  cron: "0 2 * * *",
  remark: "\u6BCF\u5929\u51CC\u66682\u70B9\u6E05\u7406\u8FC7\u671F\u4F1A\u8BDD"
});
