// services/seed.ts
var SeedLog = model.seed_log;
var seeds = new Map;
function register3(seed) {
  seeds.set(seed.name, seed);
}
function registerMany(seedList) {
  for (const seed of seedList) {
    register3(seed);
  }
}
async function isExecuted(name) {
  const log4 = await SeedLog.findOne({ where: `name = '${name}' && status = 1` });
  return !!log4;
}
async function getLogs() {
  return await SeedLog.findMany({
    orderBy: [{ column: "executedAt", order: "DESC" }]
  });
}
async function runSeed(name, force = false) {
  const seed = seeds.get(name);
  if (!seed) {
    return { success: false, message: `Seed "${name}" \u4E0D\u5B58\u5728` };
  }
  if (!force && await isExecuted(name)) {
    return { success: false, message: `Seed "${name}" \u5DF2\u6267\u884C\u8FC7` };
  }
  const now = new Date().toISOString();
  const failedLog = await SeedLog.findOne({ where: `name = '${name}' && status = 0` });
  if (failedLog) {
    await SeedLog.delete(failedLog.id);
  }
  try {
    await seed.run();
    await SeedLog.create({
      name: seed.name,
      description: seed.description || null,
      executedAt: now,
      status: 1,
      errorMessage: null
    });
    return { success: true, message: `Seed "${name}" \u6267\u884C\u6210\u529F` };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    await SeedLog.create({
      name: seed.name,
      description: seed.description || null,
      executedAt: now,
      status: 0,
      errorMessage
    });
    return { success: false, message: `Seed "${name}" \u6267\u884C\u5931\u8D25: ${errorMessage}` };
  }
}
async function runAll(force = false) {
  const results = [];
  let success2 = 0;
  let failed = 0;
  let skipped = 0;
  for (const [name, seed] of seeds) {
    if (!force && await isExecuted(name)) {
      results.push({ name, skipped: true, message: "\u5DF2\u6267\u884C\u8FC7" });
      skipped++;
      continue;
    }
    const result = await runSeed(name, force);
    results.push({ name, ...result });
    if (result.success) {
      success2++;
    } else {
      failed++;
    }
  }
  return { total: seeds.size, success: success2, failed, skipped, results };
}
function getRegisteredSeeds() {
  return Array.from(seeds.values());
}
async function resetSeed(name) {
  const log4 = await SeedLog.findOne({ where: `name = '${name}'` });
  if (log4) {
    await SeedLog.delete(log4.id);
    return true;
  }
  return false;
}
async function autoRun() {
  console.log("[Seed] \u5F00\u59CB\u81EA\u52A8\u6267\u884C Seeds...");
  const result = await runAll(false);
  console.log(`[Seed] \u6267\u884C\u5B8C\u6210: \u603B\u8BA1 ${result.total}, \u6210\u529F ${result.success}, \u5931\u8D25 ${result.failed}`);
  for (const r2 of result.results) {
    if (r2.skipped) {
      console.log(`  - ${r2.name}: \u8DF3\u8FC7\uFF08\u5DF2\u6267\u884C\uFF09`);
    } else if (r2.success) {
      console.log(`  - ${r2.name}: \u2713 \u6210\u529F`);
    } else {
      console.log(`  - ${r2.name}: \u2717 \u5931\u8D25 - ${r2.message}`);
    }
  }
}

